   300→static sds getDotfilePath(char *envoverride, char *dotfilename) {
   301→    char *path = NULL;
   302→    sds dotPath = NULL;
   303→
   304→    /* Check the env for a dotfile override. */
   305→    path = getenv(envoverride);
   306→    if (path != NULL && *path != '\0') {
   307→        if (!strcmp("/dev/null", path)) {
   308→            return NULL;
   309→        }
   310→
   311→        /* If the env is set, return it. */
   312→        dotPath = sdsnew(path);
   313→    } else {
   314→        char *home = getenv("HOME");
   315→        if (home != NULL && *home != '\0') {
   316→            /* If no override is set use $HOME/<dotfilename>. */
   317→            dotPath = sdscatprintf(sdsempty(), "%s/%s", home, dotfilename);
   318→        }
   319→    }
   320→    return dotPath;
   321→}
