   323→/* URL-style percent decoding. */
   324→#define isHexChar(c) (isdigit(c) || (c >= 'a' && c <= 'f'))
   325→#define decodeHexChar(c) (isdigit(c) ? c - '0' : c - 'a' + 10)
   326→#define decodeHex(h, l) ((decodeHexChar(h) << 4) + decodeHexChar(l))
   327→
   328→static sds percentDecode(const char *pe, size_t len) {
   329→    const char *end = pe + len;
   330→    sds ret = sdsempty();
   331→    const char *curr = pe;
   332→
   333→    while (curr < end) {
   334→        if (*curr == '%') {
   335→            if ((end - curr) < 2) {
   336→                fprintf(stderr, "Incomplete URI encoding\n");
   337→                exit(1);
   338→            }
   339→
   340→            char h = tolower(*(++curr));
   341→            char l = tolower(*(++curr));
   342→            if (!isHexChar(h) || !isHexChar(l)) {
   343→                fprintf(stderr, "Illegal character in URI encoding\n");
   344→                exit(1);
   345→            }
   346→            char c = decodeHex(h, l);
   347→            ret = sdscatlen(ret, &c, 1);
   348→            curr++;
   349→        } else {
   350→            ret = sdscatlen(ret, curr++, 1);
   351→        }
   352→    }
   353→
   354→    return ret;
   355→}
